document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("edit-btn");if(!t)return;const o=document.querySelector('meta[name="csrf-token"]')?.content||"";t.addEventListener("click",async function handleEditClick(t){t.preventDefault(),t.stopPropagation();try{const t=await fetch("/api/enhmeroshKlimakion",{method:"POST",headers:{"Content-Type":"application/json","CSRF-Token":o},credentials:"include",body:JSON.stringify(window.dataForUpdate??{})});if(t.redirected&&t.url)return void(window.location.href=t.url);if(t.status>=300&&t.status<400){const o=t.headers.get("Location")||t.headers.get("location");if(o){const t=o.startsWith("http")?o:new URL(o,window.location.origin).toString();return void(window.location.href=t)}throw new Error(`Redirect ${t.status} χωρίς Location header`)}if(403===t.status)throw new Error("CSRF blocked (403) — η συνεδρία έληξε ή λείπει token.");if(204===t.status)return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",timer:1200,showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>{window.location.href="/symbaseis/ypologismosKlimakion"});if((t.headers.get("content-type")||"").includes("application/json")){const o=await t.json();if(!t.ok||!o?.success)throw new Error(`HTTP ${t.status} / success=${o?.success}`);return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",timer:1200,showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>{window.location.href=o.redirectUrl||"/symbaseis/ypologismosKlimakion"})}if(t.ok)return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",timer:1200,showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>{window.location.href="/symbaseis/ypologismosKlimakion"});throw new Error(`HTTP error ${t.status}`)}catch(t){await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"error",title:"Αποτυχία ενημέρωσης κλιμακίων",timer:1200,text:String(t?.message||t),showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-error custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}})}})});